 49→/// Event stream type alias.
 50→pub type EventStream = Pin<Box<dyn Stream<Item = LagoResult<EventEnvelope>> + Send>>;
 51→
 52→/// Boxed future type alias for dyn-compatible async trait methods.
 53→type BoxFuture<'a, T> = Pin<Box<dyn std::future::Future<Output = T> + Send + 'a>>;
 54→
 55→/// The primary trait for event persistence.
 56→///
 57→/// Uses boxed futures for dyn-compatibility (`Arc<dyn Journal>`).
 58→pub trait Journal: Send + Sync {
 59→    /// Append a single event. Returns the assigned sequence number.
 60→    fn append(&self, event: EventEnvelope) -> BoxFuture<'_, LagoResult<SeqNo>>;
 61→
 62→    /// Append a batch of events atomically. Returns the last assigned sequence number.
 63→    fn append_batch(&self, events: Vec<EventEnvelope>) -> BoxFuture<'_, LagoResult<SeqNo>>;
 64→
 65→    /// Read events matching a query.
 66→    fn read(&self, query: EventQuery) -> BoxFuture<'_, LagoResult<Vec<EventEnvelope>>>;
 67→
 68→    /// Look up a single event by ID.
 69→    fn get_event(&self, event_id: &EventId) -> BoxFuture<'_, LagoResult<Option<EventEnvelope>>>;
 70→
 71→    /// Get the current head sequence number for a session+branch.
 72→    fn head_seq(
 73→        &self,
 74→        session_id: &SessionId,
 75→        branch_id: &BranchId,
 76→    ) -> BoxFuture<'_, LagoResult<SeqNo>>;
 77→
 78→    /// Create a tailing stream of events.
 79→    fn stream(
 80→        &self,
 81→        session_id: SessionId,
 82→        branch_id: BranchId,
 83→        after_seq: SeqNo,
 84→    ) -> BoxFuture<'_, LagoResult<EventStream>>;
 85→
 86→    /// Create or update a session.
 87→    fn put_session(&self, session: Session) -> BoxFuture<'_, LagoResult<()>>;
 88→
 89→    /// Get a session by ID.
 90→    fn get_session(&self, session_id: &SessionId) -> BoxFuture<'_, LagoResult<Option<Session>>>;
 91→
 92→    /// List all sessions.
 93→    fn list_sessions(&self) -> BoxFuture<'_, LagoResult<Vec<Session>>>;
 94→}
