 54→            branch_id: BranchId::from_string("main"),
 55→            run_id: None,
 56→            seq,
 57→            timestamp: 1_700_000_000_000_000,
 58→            parent_id: None,
 59→            payload,
 60→            metadata: HashMap::new(),
 61→            schema_version: 1,
 62→        }
 63→    }
