 19→#[derive(Debug, Default)]
 20→struct BaselineModelProvider;
 21→
 22→#[async_trait]
 23→impl ModelProviderPort for BaselineModelProvider {
 24→    async fn complete(&self, request: ModelCompletionRequest) -> KernelResult<ModelCompletion> {
 25→        let mut directives = Vec::new();
 26→        let mut stop_reason = ModelStopReason::Completed;
 27→        let mut final_answer = Some(format!("objective received: {}", request.objective));
 28→
 29→        if let Some(call) = request.proposed_tool {
 30→            directives.push(ModelDirective::ToolCall { call });
 31→            stop_reason = ModelStopReason::ToolCall;
 32→            final_answer = None;
 33→        } else {
 34→            directives.push(ModelDirective::Message {
 35→                role: "assistant".to_owned(),
 36→                content: format!("working on: {}", request.objective),
 37→            });
 38→            directives.push(ModelDirective::TextDelta {
 39→                delta: " done".to_owned(),
 40→                index: Some(0),
 41→            });
 42→        }
 43→
 44→        Ok(ModelCompletion {
 45→            provider: "baseline".to_owned(),
 46→            model: "baseline-deterministic".to_owned(),
 47→            directives,
 48→            stop_reason,
 49→            usage: Some(TokenUsage {
 50→                prompt_tokens: 8,
 51→                completion_tokens: 12,
 52→                total_tokens: 20,
 53→            }),
 54→            final_answer,
 55→        })
 56→    }
 57→}
