 59→#[derive(Debug, Clone)]
 60→pub struct KernelBuilder {
 61→    root: PathBuf,
 62→    allowed_commands: Vec<String>,
 63→    default_policy: PolicySet,
 64→}
 65→
 66→impl KernelBuilder {
 67→    pub fn new(root: impl Into<PathBuf>) -> Self {
 68→        Self {
 69→            root: root.into(),
 70→            allowed_commands: vec!["echo".to_owned(), "git".to_owned(), "cargo".to_owned()],
 71→            default_policy: PolicySet::default(),
 72→        }
 73→    }
 74→
 75→    pub fn allowed_commands(mut self, allowed_commands: Vec<String>) -> Self {
 76→        self.allowed_commands = allowed_commands;
 77→        self
 78→    }
 79→
 80→    pub fn default_policy(mut self, policy: PolicySet) -> Self {
 81→        self.default_policy = policy;
 82→        self
 83→    }
 84→
 85→    pub fn build(self) -> AiosKernel {
 86→        let events_root = self.root.join("kernel");
 87→
 88→        let event_store_backend = Arc::new(FileEventStore::new(events_root));
 89→        let stream = EventStreamHub::new(1024);
 90→        let journal = Arc::new(EventJournal::new(event_store_backend, stream));
 91→        let event_store: Arc<dyn EventStorePort> = journal;
 92→
 93→        let approvals_engine = Arc::new(ApprovalQueue::default());
 94→        let approvals: Arc<dyn aios_protocol::ApprovalPort> = approvals_engine;
 95→        let policy_engine = Arc::new(SessionPolicyEngine::new(self.default_policy));
 96→        let policy_gate: Arc<dyn PolicyGatePort> = policy_engine.clone();
 97→
 98→        let registry = Arc::new(ToolRegistry::with_core_tools());
 99→        let sandbox = Arc::new(LocalSandboxRunner::new(self.allowed_commands));
100→        let dispatcher = Arc::new(ToolDispatcher::new(registry, policy_engine, sandbox));
101→        let tool_harness: Arc<dyn ToolHarnessPort> = dispatcher;
102→
103→        let provider: Arc<dyn ModelProviderPort> = Arc::new(BaselineModelProvider);
104→        let runtime = KernelRuntime::new(
105→            RuntimeConfig::new(self.root),
106→            event_store,
107→            provider,
108→            tool_harness,
109→            approvals,
110→            policy_gate,
111→        );
112→
113→        AiosKernel { runtime }
114→    }
115→}
