 13→
 14→/// Maximum number of pending WAL entries before backpressure.
 15→const _MAX_PENDING: u64 = 10_000;
 16→
 17→pub struct IngestServer<J: Journal> {
 18→    journal: Arc<J>,
 19→}
 20→
 21→impl<J: Journal> IngestServer<J> {
 22→    pub fn new(journal: Arc<J>) -> Self {
 23→        Self { journal }
 24→    }
 25→}
 26→
 27→#[tonic::async_trait]
 28→impl<J: Journal + 'static> IngestService for IngestServer<J> {
 29→    type IngestStream = ReceiverStream<Result<proto::IngestResponse, Status>>;
 30→
 31→    async fn ingest(
 32→        &self,
 33→        request: Request<Streaming<proto::IngestRequest>>,
 34→    ) -> Result<Response<Self::IngestStream>, Status> {
 35→        let journal = Arc::clone(&self.journal);
 36→        let mut in_stream = request.into_inner();
 37→        let (tx, rx) = mpsc::channel(256);
 38→
 39→        tokio::spawn(async move {
 40→            while let Some(result) = in_stream.next().await {
 41→                match result {
 42→                    Ok(req) => {
 43→                        let Some(message) = req.message else {
 44→                            continue;
 45→                        };
 46→
 47→                        match message {
 48→                            proto::ingest_request::Message::Event(proto_event) => {
 49→                                let event_id = proto_event.event_id.clone();
 50→                                match codec::event_from_proto(proto_event) {
 51→                                    Ok(event) => match journal.append(event).await {
 52→                                        Ok(seq) => {
 53→                                            let ack = codec::make_ack(&event_id, seq, true, None);
 54→                                            let resp = proto::IngestResponse {
 55→                                                message: Some(
 56→                                                    proto::ingest_response::Message::Ack(ack),
 57→                                                ),
 58→                                            };
 59→                                            if tx.send(Ok(resp)).await.is_err() {
 60→                                                break;
 61→                                            }
 62→                                        }
 63→                                        Err(e) => {
 64→                                            error!("journal append error: {e}");
 65→                                            let ack = codec::make_ack(
 66→                                                &event_id,
 67→                                                0,
 68→                                                false,
 69→                                                Some(e.to_string()),
 70→                                            );
 71→                                            let resp = proto::IngestResponse {
 72→                                                message: Some(
 73→                                                    proto::ingest_response::Message::Ack(ack),
 74→                                                ),
 75→                                            };
 76→                                            let _ = tx.send(Ok(resp)).await;
 77→                                        }
 78→                                    },
 79→                                    Err(e) => {
 80→                                        warn!("proto decode error: {e}");
 81→                                        let ack = codec::make_ack(
 82→                                            &event_id,
 83→                                            0,
 84→                                            false,
 85→                                            Some(format!("decode error: {e}")),
 86→                                        );
 87→                                        let resp = proto::IngestResponse {
 88→                                            message: Some(proto::ingest_response::Message::Ack(
 89→                                                ack,
 90→                                            )),
 91→                                        };
 92→                                        let _ = tx.send(Ok(resp)).await;
 93→                                    }
 94→                                }
 95→                            }
 96→                            proto::ingest_request::Message::Heartbeat(_) => {
 97→                                let hb = codec::make_heartbeat();
 98→                                let resp = proto::IngestResponse {
 99→                                    message: Some(proto::ingest_response::Message::Heartbeat(hb)),
100→                                };
101→                                let _ = tx.send(Ok(resp)).await;
102→                            }
103→                        }
104→                    }
105→                    Err(e) => {
106→                        error!("stream error: {e}");
107→                        break;
108→                    }
109→                }
110→            }
111→            info!("ingest stream closed");
112→        });
113→
114→        Ok(Response::new(ReceiverStream::new(rx)))
115→    }
