117→    async fn create_session(
118→        &self,
119→        request: Request<proto::CreateSessionRequest>,
120→    ) -> Result<Response<proto::CreateSessionResponse>, Status> {
121→        let req = request.into_inner();
122→        let session_id = SessionId::from_string(&req.session_id);
123→        let config = req.config.unwrap_or_default();
124→
125→        let session = Session {
126→            session_id: session_id.clone(),
127→            config: SessionConfig {
128→                name: config.name.clone(),
129→                model: config.model.clone(),
130→                params: config.params,
131→            },
132→            created_at: CoreEvent::now_micros(),
133→            branches: vec![],
134→        };
135→
136→        self.journal
137→            .put_session(session)
138→            .await
139→            .map_err(|e| Status::internal(e.to_string()))?;
140→
141→        Ok(Response::new(proto::CreateSessionResponse {
142→            session_id: req.session_id,
143→            created: true,
