  6→/// Convert a core EventEnvelope to a proto EventEnvelope.
  7→pub fn event_to_proto(event: &EventEnvelope) -> proto::EventEnvelope {
  8→    proto::EventEnvelope {
  9→        event_id: event.event_id.to_string(),
 10→        session_id: event.session_id.to_string(),
 11→        branch_id: event.branch_id.to_string(),
 12→        run_id: event.run_id.as_ref().map(|r| r.to_string()),
 13→        seq: event.seq,
 14→        timestamp: event.timestamp,
 15→        parent_id: event.parent_id.as_ref().map(|p| p.to_string()),
 16→        payload_json: serde_json::to_string(&event.payload).unwrap_or_default(),
 17→        metadata: event.metadata.clone(),
 18→    }
 19→}
 20→
 21→/// Convert a proto EventEnvelope to a core EventEnvelope.
 22→pub fn event_from_proto(proto: proto::EventEnvelope) -> Result<EventEnvelope, serde_json::Error> {
 23→    let payload: EventPayload = serde_json::from_str(&proto.payload_json)?;
 24→
 25→    Ok(EventEnvelope {
 26→        event_id: EventId::from_string(proto.event_id),
 27→        session_id: SessionId::from_string(proto.session_id),
 28→        branch_id: BranchId::from_string(proto.branch_id),
 29→        run_id: proto.run_id.map(RunId::from_string),
 30→        seq: proto.seq,
 31→        timestamp: proto.timestamp,
 32→        parent_id: proto.parent_id.map(EventId::from_string),
 33→        payload,
 34→        metadata: proto.metadata,
 35→        schema_version: 1,
 36→    })
 37→}
