 39→/// Create a proto Ack.
 40→pub fn make_ack(event_id: &str, seq: u64, success: bool, error: Option<String>) -> proto::Ack {
 41→    proto::Ack {
 42→        event_id: event_id.to_string(),
 43→        seq,
 44→        success,
 45→        error,
 46→    }
 47→}
 48→
 49→/// Create a proto Heartbeat.
 50→pub fn make_heartbeat() -> proto::Heartbeat {
 51→    proto::Heartbeat {
 52→        timestamp: EventEnvelope::now_micros(),
 53→    }
 54→}
