 229→    pub async fn tick(&self, session_id: &SessionId, input: TickInput) -> Result<TickOutput> {
 230→        self.tick_on_branch(session_id, &BranchId::main(), input)
 231→            .await
 232→    }
 233→
 234→    #[instrument(
 235→        skip(self, input),
 236→        fields(
 237→            session_id = %session_id,
 238→            branch = %branch_id.as_str(),
 239→            objective_len = input.objective.len(),
 240→            has_tool = input.proposed_tool.is_some()
 241→        )
 242→    )]
 243→    pub async fn tick_on_branch(
 244→        &self,
 245→        session_id: &SessionId,
 246→        branch_id: &BranchId,
 247→        input: TickInput,
 248→    ) -> Result<TickOutput> {
 249→        let (manifest, mut state) = {
 250→            let sessions = self.sessions.lock();
 251→            let session = sessions
 252→                .get(session_id.as_str())
 253→                .with_context(|| format!("session not found: {session_id}"))?;
 254→            (session.manifest.clone(), session.state_vector.clone())
 255→        };
 256→
 257→        let mut emitted = 0_u64;
 258→
 259→        emitted += self
 260→            .emit_phase(session_id, branch_id, LoopPhase::Perceive)
 261→            .await?;
 262→        emitted += self
 263→            .emit_phase(session_id, branch_id, LoopPhase::Deliberate)
 264→            .await?;
 265→
 266→        self.append_event(
 267→            session_id,
 268→            branch_id,
 269→            EventKind::DeliberationProposed {
 270→                summary: input.objective.clone(),
 271→                proposed_tool: input.proposed_tool.as_ref().map(|c| c.tool_name.clone()),
 272→            },
 273→        )
 274→        .await?;
 275→        emitted += 1;
 276→
 277→        let pending_approvals = self
 278→            .approvals
 279→            .list_pending(session_id.clone())
 280→            .await
 281→            .unwrap_or_default();
 282→        let mut mode = self.estimate_mode(&state, pending_approvals.len());
 283→
 284→        self.append_event(
 285→            session_id,
 286→            branch_id,
 287→            EventKind::StateEstimated {
 288→                state: state.clone(),
 289→                mode,
 290→            },
 291→        )
 292→        .await?;
 293→        emitted += 1;
 294→        debug!(mode = ?mode, uncertainty = state.uncertainty, "state estimated");
 295→
 296→        if matches!(mode, OperatingMode::AskHuman | OperatingMode::Sleep) {
 297→            emitted += self
 298→                .finalize_tick(session_id, branch_id, &manifest, &mut state, &mode)
 299→                .await?;
 300→            return self
 301→                .current_tick_output(session_id, branch_id, mode, state, emitted)
 302→                .await;
 303→        }
 304→
 305→        let run_id = RunId::default();
 306→        self.append_event(
 307→            session_id,
 308→            branch_id,
 309→            EventKind::RunStarted {
 310→                provider: "canonical".to_owned(),
 311→                max_iterations: 1,
 312→            },
 313→        )
 314→        .await?;
 315→        emitted += 1;
 316→        self.append_event(session_id, branch_id, EventKind::StepStarted { index: 0 })
 317→            .await?;
 318→        emitted += 1;
 319→
 320→        let completion = if let Some(call) = input.proposed_tool.clone() {
 321→            Ok(aios_protocol::ModelCompletion {
 322→                provider: "inline-proposed-tool".to_owned(),
 323→                model: "inline".to_owned(),
 324→                directives: vec![ModelDirective::ToolCall { call }],
 325→                stop_reason: aios_protocol::ModelStopReason::ToolCall,
 326→                usage: None,
 327→                final_answer: None,
 328→            })
 329→        } else {
 330→            self.provider
 331→                .complete(ModelCompletionRequest {
 332→                    session_id: session_id.clone(),
 333→                    branch_id: branch_id.clone(),
 334→                    run_id: run_id.clone(),
 335→                    step_index: 0,
 336→                    objective: input.objective.clone(),
 337→                    proposed_tool: None,
 338→                })
 339→                .await
 340→                .map_err(|error| anyhow::anyhow!(error.to_string()))
 341→        };
 342→
 343→        match completion {
 344→            Ok(completion) => {
 345→                let mut directive_count = 0_usize;
 346→                for directive in completion.directives {
 347→                    directive_count += 1;
 348→                    match directive {
 349→                        ModelDirective::TextDelta { delta, index } => {
 350→                            self.append_event(
 351→                                session_id,
 352→                                branch_id,
 353→                                EventKind::TextDelta { delta, index },
 354→                            )
 355→                            .await?;
 356→                            emitted += 1;
 357→                        }
 358→                        ModelDirective::Message { role, content } => {
 359→                            self.append_event(
 360→                                session_id,
 361→                                branch_id,
 362→                                EventKind::Message {
 363→                                    role,
 364→                                    content,
 365→                                    model: Some(completion.model.clone()),
 366→                                    token_usage: completion.usage,
 367→                                },
 368→                            )
 369→                            .await?;
 370→                            emitted += 1;
 371→                        }
 372→                        ModelDirective::ToolCall { call } => {
 373→                            emitted += self
 374→                                .emit_phase(session_id, branch_id, LoopPhase::Gate)
 375→                                .await?;
 376→                            self.append_event(
 377→                                session_id,
 378→                                branch_id,
 379→                                EventKind::ToolCallRequested {
 380→                                    call_id: call.call_id.clone(),
 381→                                    tool_name: call.tool_name.clone(),
 382→                                    arguments: call.input.clone(),
 383→                                    category: None,
 384→                                },
 385→                            )
 386→                            .await?;
 387→                            emitted += 1;
 388→
 389→                            let policy = self
 390→                                .policy_gate
 391→                                .evaluate(session_id.clone(), call.requested_capabilities.clone())
 392→                                .await
 393→                                .map_err(|error| anyhow::anyhow!(error.to_string()))?;
 394→
 395→                            if !policy.denied.is_empty() {
 396→                                mode = OperatingMode::Recover;
 397→                                state.error_streak += 1;
 398→                                state.uncertainty = (state.uncertainty + 0.15).min(1.0);
 399→                                state.budget.error_budget_remaining =
 400→                                    state.budget.error_budget_remaining.saturating_sub(1);
 401→                                self.append_event(
 402→                                    session_id,
 403→                                    branch_id,
 404→                                    EventKind::ToolCallFailed {
 405→                                        call_id: call.call_id.clone(),
 406→                                        tool_name: call.tool_name.clone(),
 407→                                        error: format!(
 408→                                            "capabilities denied: {}",
 409→                                            policy
 410→                                                .denied
 411→                                                .iter()
 412→                                                .map(|capability| capability.as_str())
 413→                                                .collect::<Vec<_>>()
 414→                                                .join(",")
 415→                                        ),
 416→                                    },
 417→                                )
 418→                                .await?;
 419→                                emitted += 1;
 420→                                continue;
 421→                            }
 422→
 423→                            if !policy.requires_approval.is_empty() {
 424→                                mode = OperatingMode::AskHuman;
 425→                                for capability in policy.requires_approval {
 426→                                    let ticket = self
 427→                                        .approvals
 428→                                        .enqueue(ApprovalRequest {
 429→                                            session_id: session_id.clone(),
 430→                                            call_id: call.call_id.clone(),
 431→                                            tool_name: call.tool_name.clone(),
 432→                                            capability: capability.clone(),
 433→                                            reason: format!(
 434→                                                "approval required for tool {}",
 435→                                                call.tool_name
 436→                                            ),
 437→                                        })
 438→                                        .await
 439→                                        .map_err(|error| anyhow::anyhow!(error.to_string()))?;
 440→                                    self.append_event(
 441→                                        session_id,
 442→                                        branch_id,
 443→                                        EventKind::ApprovalRequested {
 444→                                            approval_id: ticket.approval_id,
 445→                                            call_id: call.call_id.clone(),
 446→                                            tool_name: call.tool_name.clone(),
 447→                                            arguments: call.input.clone(),
 448→                                            risk: RiskLevel::Medium,
 449→                                        },
 450→                                    )
 451→                                    .await?;
 452→                                    emitted += 1;
 453→                                }
 454→                                continue;
 455→                            }
 456→
 457→                            emitted += self
 458→                                .emit_phase(session_id, branch_id, LoopPhase::Execute)
 459→                                .await?;
 460→                            let report = self
 461→                                .tool_harness
 462→                                .execute(ToolExecutionRequest {
 463→                                    session_id: session_id.clone(),
 464→                                    workspace_root: manifest.workspace_root.clone(),
 465→                                    call: call.clone(),
 466→                                })
 467→                                .await
 468→                                .map_err(|error| anyhow::anyhow!(error.to_string()));
 469→                            match report {
 470→                                Ok(report) => {
 471→                                    emitted += self
 472→                                        .record_tool_report(
 473→                                            session_id, branch_id, &manifest, &report,
 474→                                        )
 475→                                        .await?;
 476→                                    self.apply_homeostasis_controllers(&mut state, &report);
 477→                                    mode = self.estimate_mode(&state, 0);
 478→                                    info!(
 479→                                        tool_name = %report.tool_name,
 480→                                        tool_run_id = %report.tool_run_id,
 481→                                        exit_status = report.exit_status,
 482→                                        mode = ?mode,
 483→                                        "tool execution completed"
 484→                                    );
 485→                                }
 486→                                Err(error) => {
 487→                                    state.error_streak += 1;
 488→                                    state.uncertainty = (state.uncertainty + 0.15).min(1.0);
 489→                                    state.budget.error_budget_remaining =
 490→                                        state.budget.error_budget_remaining.saturating_sub(1);
 491→                                    mode = OperatingMode::Recover;
 492→                                    warn!(
 493→                                        error = %error,
 494→                                        error_streak = state.error_streak,
 495→                                        "tool execution failed"
 496→                                    );
 497→                                    self.append_event(
 498→                                        session_id,
 499→                                        branch_id,
 500→                                        EventKind::ToolCallFailed {
 501→                                            call_id: call.call_id.clone(),
 502→                                            tool_name: call.tool_name.clone(),
 503→                                            error: error.to_string(),
 504→                                        },
 505→                                    )
 506→                                    .await?;
 507→                                    emitted += 1;
 508→                                }
 509→                            }
 510→                        }
 511→                    }
 512→                }
 513→
 514→                self.append_event(
 515→                    session_id,
 516→                    branch_id,
 517→                    EventKind::StepFinished {
 518→                        index: 0,
 519→                        stop_reason: model_stop_reason_string(&completion.stop_reason),
 520→                        directive_count,
 521→                    },
 522→                )
 523→                .await?;
 524→                emitted += 1;
 525→
 526→                self.append_event(
 527→                    session_id,
 528→                    branch_id,
 529→                    EventKind::RunFinished {
 530→                        reason: model_stop_reason_string(&completion.stop_reason),
 531→                        total_iterations: 1,
 532→                        final_answer: completion.final_answer,
 533→                        usage: completion.usage,
 534→                    },
 535→                )
 536→                .await?;
 537→                emitted += 1;
 538→            }
 539→            Err(error) => {
 540→                mode = OperatingMode::Recover;
 541→                state.error_streak += 1;
 542→                state.uncertainty = (state.uncertainty + 0.15).min(1.0);
 543→                state.budget.error_budget_remaining =
 544→                    state.budget.error_budget_remaining.saturating_sub(1);
 545→                self.append_event(
 546→                    session_id,
 547→                    branch_id,
 548→                    EventKind::RunErrored {
 549→                        error: error.to_string(),
 550→                    },
 551→                )
 552→                .await?;
 553→                emitted += 1;
 554→            }
 555→        }
 556→
 557→        if state.error_streak >= self.config.circuit_breaker_errors {
 558→            mode = OperatingMode::Recover;
 559→            warn!(
 560→                error_streak = state.error_streak,
 561→                threshold = self.config.circuit_breaker_errors,
 562→                "circuit breaker tripped"
 563→            );
 564→            self.append_event(
 565→                session_id,
 566→                branch_id,
 567→                EventKind::CircuitBreakerTripped {
 568→                    reason: "error streak exceeded threshold".to_owned(),
 569→                    error_streak: state.error_streak,
 570→                },
 571→            )
 572→            .await?;
 573→            emitted += 1;
 574→        }
 575→
 576→        emitted += self
 577→            .finalize_tick(session_id, branch_id, &manifest, &mut state, &mode)
 578→            .await?;
 579→        info!(mode = ?mode, emitted, "tick finalized");
 580→        self.current_tick_output(session_id, branch_id, mode, state, emitted)
 581→            .await
 582→    }
 583→
 584→    #[instrument(
 585→        skip(self),
 586→        fields(
 587→            session_id = %session_id,
 588→            branch = %branch_id.as_str(),
 589→            from_branch = ?from_branch.as_ref().map(|branch| branch.as_str())
 590→        )
 591→    )]
 592→    pub async fn create_branch(
 593→        &self,
 594→        session_id: &SessionId,
 595→        branch_id: BranchId,
 596→        from_branch: Option<BranchId>,
 597→        fork_sequence: Option<u64>,
 598→    ) -> Result<BranchInfo> {
 599→        let from_branch = from_branch.unwrap_or_else(BranchId::main);
 600→        let fork_sequence_value = {
 601→            let mut sessions = self.sessions.lock();
 602→            let session = sessions
 603→                .get_mut(session_id.as_str())
 604→                .with_context(|| format!("session not found: {session_id}"))?;
 605→            if session.branches.contains_key(&branch_id) {
 606→                bail!("branch already exists: {}", branch_id.as_str());
 607→            }
 608→            let parent = session
 609→                .branches
 610→                .get(&from_branch)
 611→                .with_context(|| format!("source branch not found: {}", from_branch.as_str()))?;
 612→            if let Some(target) = &parent.merged_into {
 613→                bail!(
 614→                    "source branch {} is merged into {} and is read-only",
 615→                    from_branch.as_str(),
 616→                    target.as_str()
 617→                );
 618→            }
 619→            let fork = fork_sequence.unwrap_or(parent.head_sequence);
 620→            if fork > parent.head_sequence {
 621→                bail!(
 622→                    "fork sequence {} exceeds source branch head {}",
 623→                    fork,
 624→                    parent.head_sequence
 625→                );
 626→            }
 627→
 628→            session.next_sequence_by_branch.insert(branch_id.clone(), 1);
 629→            session.branches.insert(
 630→                branch_id.clone(),
 631→                BranchRuntimeState {
 632→                    parent_branch: Some(from_branch.clone()),
 633→                    fork_sequence: fork,
 634→                    head_sequence: 0,
 635→                    merged_into: None,
 636→                },
 637→            );
 638→            fork
 639→        };
 640→
 641→        self.append_event(
 642→            session_id,
 643→            &branch_id,
 644→            EventKind::BranchCreated {
 645→                new_branch_id: branch_id.clone(),
 646→                fork_point_seq: fork_sequence_value,
 647→                name: branch_id.as_str().to_owned(),
 648→            },
 649→        )
 650→        .await?;
 651→        info!(
 652→            branch = %branch_id.as_str(),
 653→            from_branch = %from_branch.as_str(),
 654→            fork_sequence = fork_sequence_value,
 655→            "branch created"
 656→        );
 657→
 658→        self.branch_info(session_id, &branch_id)
 659→    }
