 867→    fn estimate_mode(&self, state: &AgentStateVector, pending_approvals: usize) -> OperatingMode {
 868→        if pending_approvals > 0 {
 869→            return OperatingMode::AskHuman;
 870→        }
 871→
 872→        if state.error_streak >= self.config.circuit_breaker_errors {
 873→            return OperatingMode::Recover;
 874→        }
 875→
 876→        if state.progress >= 0.98 {
 877→            return OperatingMode::Sleep;
 878→        }
 879→
 880→        if state.context_pressure > 0.8 || state.uncertainty > 0.65 {
 881→            return OperatingMode::Explore;
 882→        }
 883→
 884→        if state.side_effect_pressure > 0.6 {
 885→            return OperatingMode::Verify;
 886→        }
 887→
 888→        OperatingMode::Execute
 889→    }
