 891→    fn apply_homeostasis_controllers(
 892→        &self,
 893→        state: &mut AgentStateVector,
 894→        report: &ToolExecutionReport,
 895→    ) {
 896→        state.budget.tool_calls_remaining = state.budget.tool_calls_remaining.saturating_sub(1);
 897→        state.budget.tokens_remaining = state.budget.tokens_remaining.saturating_sub(750);
 898→        state.budget.time_remaining_ms = state.budget.time_remaining_ms.saturating_sub(1200);
 899→
 900→        if report.exit_status == 0 {
 901→            state.progress = (state.progress + 0.12).min(1.0);
 902→            state.uncertainty = (state.uncertainty * 0.85).max(0.05);
 903→            state.error_streak = 0;
 904→            state.side_effect_pressure = (state.side_effect_pressure + 0.2).min(1.0);
 905→        } else {
 906→            state.error_streak += 1;
 907→            state.uncertainty = (state.uncertainty + 0.18).min(1.0);
 908→            state.budget.error_budget_remaining =
 909→                state.budget.error_budget_remaining.saturating_sub(1);
 910→            state.side_effect_pressure = (state.side_effect_pressure * 0.5).max(0.1);
 911→        }
 912→
 913→        state.context_pressure = (state.context_pressure + 0.03).min(1.0);
 914→        state.human_dependency = if state.error_streak >= 2 { 0.6 } else { 0.0 };
 915→
 916→        state.risk_level = if state.uncertainty > 0.75 || state.side_effect_pressure > 0.7 {
 917→            RiskLevel::High
 918→        } else if state.uncertainty > 0.45 || state.side_effect_pressure > 0.4 {
 919→            RiskLevel::Medium
 920→        } else {
 921→            RiskLevel::Low
 922→        };
 923→    }
