 925→    async fn finalize_tick(
 926→        &self,
 927→        session_id: &SessionId,
 928→        branch_id: &BranchId,
 929→        manifest: &SessionManifest,
 930→        state: &mut AgentStateVector,
 931→        mode: &OperatingMode,
 932→    ) -> Result<u64> {
 933→        let mut emitted = 0_u64;
 934→
 935→        emitted += self
 936→            .emit_phase(session_id, branch_id, LoopPhase::Reflect)
 937→            .await?;
 938→
 939→        self.append_event(
 940→            session_id,
 941→            branch_id,
 942→            EventKind::BudgetUpdated {
 943→                budget: state.budget.clone(),
 944→                reason: "tick accounting".to_owned(),
 945→            },
 946→        )
 947→        .await?;
 948→        emitted += 1;
 949→
 950→        self.append_event(
 951→            session_id,
 952→            branch_id,
 953→            EventKind::StateEstimated {
 954→                state: state.clone(),
 955→                mode: *mode,
 956→            },
 957→        )
 958→        .await?;
 959→        emitted += 1;
 960→
 961→        let checkpoint_id = if self.should_checkpoint(session_id)? {
 962→            let checkpoint = self
 963→                .create_checkpoint(session_id, branch_id, manifest, state)
 964→                .await?;
 965→            self.append_event(
 966→                session_id,
 967→                branch_id,
 968→                EventKind::CheckpointCreated {
 969→                    checkpoint_id: checkpoint.checkpoint_id.clone(),
 970→                    event_sequence: checkpoint.event_sequence,
 971→                    state_hash: checkpoint.state_hash.clone(),
 972→                },
 973→            )
 974→            .await?;
 975→            emitted += 1;
 976→            Some(checkpoint.checkpoint_id)
 977→        } else {
 978→            None
 979→        };
 980→
 981→        self.write_heartbeat(session_id, state, mode).await?;
 982→        self.append_event(
 983→            session_id,
 984→            branch_id,
 985→            EventKind::Heartbeat {
 986→                summary: "tick complete".to_owned(),
 987→                checkpoint_id,
 988→            },
 989→        )
 990→        .await?;
 991→        emitted += 1;
 992→
 993→        emitted += self
 994→            .emit_phase(session_id, branch_id, LoopPhase::Sleep)
 995→            .await?;
 996→
 997→        self.persist_runtime_state(session_id, state.clone(), *mode)?;
 998→
 999→        Ok(emitted)
1000→    }
