1120→    async fn append_event(
1121→        &self,
1122→        session_id: &SessionId,
1123→        branch_id: &BranchId,
1124→        kind: EventKind,
1125→    ) -> Result<()> {
1126→        let event_kind = event_kind_name(&kind);
1127→        let sequence = self.next_sequence(session_id, branch_id)?;
1128→        debug!(
1129→            session_id = %session_id,
1130→            branch = %branch_id.as_str(),
1131→            sequence,
1132→            event_kind,
1133→            "appending event"
1134→        );
1135→        let event = EventRecord::new(session_id.clone(), branch_id.clone(), sequence, kind);
1136→        let persisted = match self.event_store.append(event).await {
1137→            Ok(persisted) => persisted,
1138→            Err(append_error) => {
1139→                if let Err(resync_error) = self.resync_next_sequence(session_id, branch_id).await {
1140→                    warn!(
1141→                        session_id = %session_id,
1142→                        branch = %branch_id.as_str(),
1143→                        error = %append_error,
1144→                        resync_error = %resync_error,
1145→                        "event append failed and sequence resync failed"
1146→                    );
1147→                    return Err(anyhow::anyhow!(append_error.to_string())).context(format!(
1148→                        "failed appending event and failed sequence resync: {resync_error}"
1149→                    ));
1150→                }
1151→                warn!(
1152→                    session_id = %session_id,
1153→                    branch = %branch_id.as_str(),
1154→                    error = %append_error,
1155→                    "event append failed; sequence resynced"
1156→                );
1157→                return Err(anyhow::anyhow!(append_error.to_string()))
1158→                    .context("failed appending event; sequence was resynced");
1159→            }
1160→        };
1161→        let _ = self.stream.send(persisted.clone());
1162→        self.mark_branch_head(session_id, branch_id, persisted.sequence)?;
1163→        Ok(())
1164→    }
