1342→            .get_mut(session_id.as_str())
1343→            .with_context(|| format!("session not found: {session_id}"))?;
1344→        session.state_vector = state.clone();
1345→        session.mode = mode;
1346→
1347→        // Sync lakebase at the workspace root
1348→        if let Some(parent) = self.config.root.parent() {
1349→            let lake_dir = parent.join(".lake");
1350→            let state_json = serde_json::to_string_pretty(&state).unwrap_or_default();
1351→            let mode_str = match mode {
1352→                OperatingMode::Explore => "explore",
1353→                OperatingMode::Execute => "execute",
1354→                OperatingMode::Verify => "verify",
1355→                OperatingMode::AskHuman => "ask_human",
1356→                OperatingMode::Recover => "recover",
1357→                OperatingMode::Sleep => "sleep",
1358→            };
1359→
1360→            // Fire and forget IO, but in an async context we need to spawn it or do it blocking
1361→            // Since this is a synchronous function, we can't await. Let's spawn it.
1362→            let lake_dir_clone = lake_dir.clone();
1363→            tokio::spawn(async move {
1364→                let _ = fs::create_dir_all(&lake_dir_clone).await;
1365→                let _ = fs::write(lake_dir_clone.join("state.json"), state_json).await;
1366→                let _ = fs::write(lake_dir_clone.join("mode.txt"), mode_str).await;
1367→            });
1368→        }
1369→
1370→        Ok(())
1371→    }
