  7→
  8→/// A [`SessionRepository`] implementation backed by a Lago [`Journal`].
  9→///
 10→/// This bridges Arcan's synchronous `SessionRepository` trait with Lago's
 11→/// async `Journal` trait. The sync/async boundary is crossed using
 12→/// `Handle::current().block_on()`, which is safe because the Arcan
 13→/// `AgentLoop` runs the orchestrator inside `tokio::task::spawn_blocking`.
 14→pub struct LagoSessionRepository {
 15→    journal: Arc<dyn Journal>,
 16→    default_branch: BranchId,
 17→}
 18→
 19→impl LagoSessionRepository {
 20→    pub fn new(journal: Arc<dyn Journal>) -> Self {
 21→        Self {
 22→            journal,
 23→            default_branch: BranchId::from("main"),
 24→        }
 25→    }
 26→
 27→    /// Run an async future on the current tokio runtime from a sync context.
 28→    fn block_on<F: std::future::Future>(&self, f: F) -> F::Output {
 29→        tokio::runtime::Handle::current().block_on(f)
 30→    }
 31→
 32→    fn session_id(&self, id: &str) -> SessionId {
 33→        SessionId::from(id.to_string())
 34→    }
 35→}
 36→
 37→impl SessionRepository for LagoSessionRepository {
 38→    fn append(&self, request: AppendEvent) -> Result<EventRecord, StoreError> {
 39→        let session_id = self.session_id(&request.session_id);
 40→        let branch_id = BranchId::from(request.branch_id.clone());
 41→        let seq: SeqNo = 0;
 42→
 43→        // Extract run_id from the event for the envelope.
 44→        let run_id = extract_run_id(&request.event);
 45→        let arcan_event_id = uuid::Uuid::new_v4().to_string();
 46→
 47→        let envelope = event_map::arcan_to_lago(
 48→            &session_id,
 49→            &branch_id,
 50→            seq,
 51→            &run_id,
 52→            &request.event,
 53→            &arcan_event_id,
 54→        );
 55→
 56→        let timestamp = DateTime::<Utc>::from_timestamp(
 57→            (envelope.timestamp / 1_000_000) as i64,
 58→            ((envelope.timestamp % 1_000_000) * 1_000) as u32,
 59→        )
 60→        .unwrap_or_else(Utc::now);
 61→
 62→        let assigned_seq =
 63→            self.block_on(self.journal.append(envelope))
 64→                .map_err(|e| StoreError::Io {
 65→                    path: "lago-journal".into(),
 66→                    source: std::io::Error::other(e.to_string()),
 67→                })?;
 68→
 69→        Ok(EventRecord {
 70→            id: arcan_event_id,
 71→            session_id: request.session_id,
 72→            branch_id: request.branch_id,
 73→            sequence: assigned_seq,
 74→            parent_id: request.parent_id,
 75→            timestamp,
 76→            event: request.event,
 77→        })
 78→    }
 79→
 80→    fn load_session(
 81→        &self,
 82→        session_id: &str,
 83→        branch_id: &str,
 84→    ) -> Result<Vec<EventRecord>, StoreError> {
 85→        let sid = self.session_id(session_id);
 86→        let query = EventQuery::new()
 87→            .session(sid.clone())
 88→            .branch(BranchId::from(branch_id.to_string()));
 89→
 90→        let envelopes = self
 91→            .block_on(self.journal.read(query))
 92→            .map_err(|e| StoreError::Io {
 93→                path: "lago-journal".into(),
 94→                source: std::io::Error::other(e.to_string()),
 95→            })?;
 96→
 97→        let mut records = Vec::with_capacity(envelopes.len());
 98→        for envelope in &envelopes {
 99→            if let Some(agent_event) = event_map::lago_to_arcan(envelope) {
100→                let arcan_id = envelope
101→                    .metadata
102→                    .get("arcan_event_id")
103→                    .cloned()
104→                    .unwrap_or_else(|| envelope.event_id.to_string());
105→
106→                let timestamp = DateTime::<Utc>::from_timestamp(
107→                    (envelope.timestamp / 1_000_000) as i64,
108→                    ((envelope.timestamp % 1_000_000) * 1_000) as u32,
109→                )
110→                .unwrap_or_else(Utc::now);
111→
112→                records.push(EventRecord {
113→                    id: arcan_id,
114→                    session_id: session_id.to_string(),
115→                    branch_id: envelope.branch_id.to_string(),
116→                    sequence: envelope.seq,
117→                    parent_id: envelope.parent_id.as_ref().map(ToString::to_string),
118→                    timestamp,
119→                    event: agent_event,
120→                });
121→            }
122→        }
123→
124→        Ok(records)
125→    }
126→
127→    fn load_children(&self, parent_id: &str) -> Result<Vec<EventRecord>, StoreError> {
128→        // Lago's journal doesn't index by parent_id natively.
129→        // For now, we scan the default branch and filter in memory.
130→        // This is acceptable because branching/child lookups are rare in the agent loop.
131→        let query = EventQuery::new().branch(self.default_branch.clone());
132→
133→        let envelopes = self
134→            .block_on(self.journal.read(query))
135→            .map_err(|e| StoreError::Io {
136→                path: "lago-journal".into(),
137→                source: std::io::Error::other(e.to_string()),
138→            })?;
139→
140→        let mut results = Vec::new();
141→        for envelope in &envelopes {
142→            let is_child = envelope
143→                .parent_id
144→                .as_ref()
145→                .is_some_and(|pid| pid.to_string() == parent_id);
146→
147→            if is_child {
148→                if let Some(agent_event) = event_map::lago_to_arcan(envelope) {
149→                    let arcan_id = envelope
150→                        .metadata
151→                        .get("arcan_event_id")
152→                        .cloned()
153→                        .unwrap_or_else(|| envelope.event_id.to_string());
154→
155→                    let timestamp = DateTime::<Utc>::from_timestamp(
156→                        (envelope.timestamp / 1_000_000) as i64,
157→                        ((envelope.timestamp % 1_000_000) * 1_000) as u32,
158→                    )
159→                    .unwrap_or_else(Utc::now);
160→
161→                    results.push(EventRecord {
162→                        id: arcan_id,
163→                        session_id: envelope.session_id.to_string(),
164→                        branch_id: envelope.branch_id.to_string(),
165→                        sequence: envelope.seq,
166→                        parent_id: Some(parent_id.to_string()),
167→                        timestamp,
168→                        event: agent_event,
169→                    });
170→                }
171→            }
172→        }
173→
174→        Ok(results)
175→    }
176→
177→    fn head(&self, session_id: &str, branch_id: &str) -> Result<Option<EventRecord>, StoreError> {
178→        let records = self.load_session(session_id, branch_id)?;
179→        Ok(records.into_iter().last())
180→    }
181→}
182→
183→fn extract_run_id(event: &AgentEvent) -> String {
184→    match event {
185→        AgentEvent::RunStarted { run_id, .. }
186→        | AgentEvent::IterationStarted { run_id, .. }
187→        | AgentEvent::ModelOutput { run_id, .. }
188→        | AgentEvent::TextDelta { run_id, .. }
189→        | AgentEvent::ToolCallRequested { run_id, .. }
190→        | AgentEvent::ToolCallCompleted { run_id, .. }
191→        | AgentEvent::ToolCallFailed { run_id, .. }
192→        | AgentEvent::StatePatched { run_id, .. }
193→        | AgentEvent::ContextCompacted { run_id, .. }
194→        | AgentEvent::ApprovalRequested { run_id, .. }
195→        | AgentEvent::ApprovalResolved { run_id, .. }
196→        | AgentEvent::RunErrored { run_id, .. }
197→        | AgentEvent::RunFinished { run_id, .. } => run_id.clone(),
198→    }
199→}
