  1→use arcan_core::protocol::AgentEvent;
  2→use lago_api::sse::format::{SseFormat, SseFrame};
  3→use lago_core::{BranchId, SessionId};
  4→
  5→use crate::event_map;
  6→
  7→/// Converts arcan `AgentEvent`s into SSE frames using any lago `SseFormat`.
  8→///
  9→/// This bridges arcan's event stream with lago's multi-format SSE system,
 10→/// supporting OpenAI, Anthropic, Vercel AI SDK, and native Lago wire formats.
 11→pub struct SseBridge {
 12→    format: Box<dyn SseFormat>,
 13→    session_id: SessionId,
 14→    branch_id: BranchId,
 15→    seq: u64,
 16→}
 17→
 18→impl SseBridge {
 19→    pub fn new(format: Box<dyn SseFormat>, session_id: &str, branch_id: &str) -> Self {
 20→        Self {
 21→            format,
 22→            session_id: SessionId::from(session_id.to_string()),
 23→            branch_id: BranchId::from(branch_id.to_string()),
 24→            seq: 0,
 25→        }
 26→    }
 27→
 28→    /// Convert an `AgentEvent` into zero or more SSE frames.
 29→    ///
 30→    /// Events that the selected format doesn't handle are silently dropped
 31→    /// (empty vec returned).
 32→    pub fn format_event(&mut self, event: &AgentEvent, run_id: &str) -> Vec<SseFrame> {
 33→        self.seq += 1;
 34→        let event_id = uuid::Uuid::new_v4().to_string();
 35→
 36→        let envelope = event_map::arcan_to_lago(
 37→            &self.session_id,
 38→            &self.branch_id,
 39→            self.seq,
 40→            run_id,
 41→            event,
 42→            &event_id,
 43→        );
 44→
 45→        self.format.format(&envelope)
 46→    }
 47→
 48→    /// Return the "done" frame for the selected format, if any.
 49→    pub fn done_frame(&self) -> Option<SseFrame> {
 50→        self.format.done_frame()
 51→    }
 52→
 53→    /// Return extra HTTP headers required by the selected format.
 54→    pub fn extra_headers(&self) -> Vec<(String, String)> {
 55→        self.format.extra_headers()
 56→    }
 57→
 58→    /// The name of the active format.
 59→    pub fn format_name(&self) -> &str {
 60→        self.format.name()
 61→    }
 62→}
 63→
 64→/// Select a lago SSE format by name.
 65→///
 66→/// Supported names: `"openai"`, `"anthropic"`, `"vercel"`, `"lago"`.
 67→/// Returns `None` for unknown format names.
 68→pub fn select_format(name: &str) -> Option<Box<dyn SseFormat>> {
 69→    match name {
 70→        "openai" => Some(Box::new(lago_api::sse::openai::OpenAiFormat)),
 71→        "anthropic" => Some(Box::new(lago_api::sse::anthropic::AnthropicFormat)),
 72→        "vercel" => Some(Box::new(lago_api::sse::vercel::VercelFormat)),
 73→        "lago" => Some(Box::new(lago_api::sse::lago::LagoFormat)),
 74→        _ => None,
 75→    }
 76→}
