  1→//! Async Stream adapter for tailing new events from the journal.
  2→
  3→use std::pin::Pin;
  4→use std::sync::Arc;
  5→use std::task::{Context, Poll};
  6→
  7→use futures::Stream;
  8→use redb::Database;
  9→use tokio::sync::broadcast;
 10→
 11→use lago_core::{BranchId, EventEnvelope, LagoError, LagoResult, SeqNo, SessionId};
 12→
 13→use crate::keys::encode_event_key;
 14→use crate::redb_journal::EventNotification;
 15→use crate::tables::EVENTS;
 16→
 17→/// A tailing stream that yields new events as they are appended to the journal.
 18→///
 19→/// Uses a broadcast receiver to be notified when new events arrive, then reads
 20→/// from the database to fetch the actual event data. This avoids polling and
 21→/// provides near-real-time event delivery.
 22→pub struct EventTailStream {
 23→    db: Arc<Database>,
 24→    rx: broadcast::Receiver<EventNotification>,
 25→    session_id: SessionId,
 26→    branch_id: BranchId,
 27→    /// The last sequence number we have yielded. We only yield events with seq > last_seq.
 28→    last_seq: SeqNo,
 29→    /// Buffer of events fetched from the DB but not yet yielded.
 30→    buffer: std::collections::VecDeque<EventEnvelope>,
 31→    /// Whether we have been notified of new events but haven't fetched them yet.
 32→    pending_fetch: bool,
 33→}
 34→
 35→impl EventTailStream {
 36→    pub fn new(
 37→        db: Arc<Database>,
 38→        rx: broadcast::Receiver<EventNotification>,
 39→        session_id: SessionId,
 40→        branch_id: BranchId,
 41→        after_seq: SeqNo,
 42→    ) -> Self {
 43→        Self {
 44→            db,
 45→            rx,
 46→            session_id,
 47→            branch_id,
 48→            last_seq: after_seq,
 49→            buffer: std::collections::VecDeque::new(),
 50→            pending_fetch: false,
 51→        }
 52→    }
 53→
 54→    /// Fetch new events from the database for our session/branch after last_seq.
 55→    fn fetch_new_events(&self) -> LagoResult<Vec<EventEnvelope>> {
 56→        let txn = self
 57→            .db
 58→            .begin_read()
 59→            .map_err(|e| LagoError::Journal(format!("begin_read failed: {e}")))?;
 60→        let table = txn
 61→            .open_table(EVENTS)
 62→            .map_err(|e| LagoError::Journal(format!("open events table: {e}")))?;
 63→
 64→        let start_seq = self.last_seq + 1;
 65→        let start_key =
 66→            encode_event_key(self.session_id.as_str(), self.branch_id.as_str(), start_seq);
 67→        let end_key = encode_event_key(self.session_id.as_str(), self.branch_id.as_str(), u64::MAX);
 68→
 69→        let range = table
 70→            .range(start_key.as_slice()..=end_key.as_slice())
 71→            .map_err(|e| LagoError::Journal(format!("range scan: {e}")))?;
 72→
 73→        let mut events = Vec::new();
 74→        for item in range {
 75→            let (_, value) = item.map_err(|e| LagoError::Journal(format!("range item: {e}")))?;
 76→            let envelope: EventEnvelope = serde_json::from_str(value.value())?;
 77→            events.push(envelope);
 78→        }
 79→        Ok(events)
 80→    }
 81→}
 82→
 83→impl Stream for EventTailStream {
 84→    type Item = LagoResult<EventEnvelope>;
 85→
 86→    fn poll_next(mut self: Pin<&mut Self>, cx: &mut Context<'_>) -> Poll<Option<Self::Item>> {
 87→        // First, drain the buffer
 88→        if let Some(event) = self.buffer.pop_front() {
 89→            self.last_seq = event.seq;
 90→            return Poll::Ready(Some(Ok(event)));
 91→        }
 92→
 93→        // If we have a pending fetch, do it now
 94→        if self.pending_fetch {
 95→            self.pending_fetch = false;
 96→            match self.fetch_new_events() {
 97→                Ok(events) => {
 98→                    for event in events {
 99→                        self.buffer.push_back(event);
100→                    }
101→                    if let Some(event) = self.buffer.pop_front() {
102→                        self.last_seq = event.seq;
103→                        return Poll::Ready(Some(Ok(event)));
104→                    }
105→                }
106→                Err(e) => return Poll::Ready(Some(Err(e))),
107→            }
108→        }
109→
110→        // Poll the broadcast receiver for notifications
111→        loop {
112→            match self.rx.try_recv() {
113→                Ok(notification) => {
114→                    // Only care about notifications for our session+branch
115→                    if notification.session_id.as_str() == self.session_id.as_str()
116→                        && notification.branch_id.as_str() == self.branch_id.as_str()
117→                        && notification.seq > self.last_seq
118→                    {
119→                        // Fetch new events from the DB
120→                        match self.fetch_new_events() {
121→                            Ok(events) => {
122→                                for event in events {
123→                                    self.buffer.push_back(event);
124→                                }
125→                                if let Some(event) = self.buffer.pop_front() {
126→                                    self.last_seq = event.seq;
127→                                    return Poll::Ready(Some(Ok(event)));
128→                                }
129→                            }
130→                            Err(e) => return Poll::Ready(Some(Err(e))),
131→                        }
132→                    }
133→                }
134→                Err(broadcast::error::TryRecvError::Empty) => {
135→                    // No notifications available; register waker and return Pending.
136→                    // We use a small trick: spawn a task that awaits the receiver
137→                    // and wakes us. This is necessary because broadcast::Receiver
138→                    // doesn't directly implement poll-based APIs in a way compatible
139→                    // with Stream.
140→                    let waker = cx.waker().clone();
141→                    let mut rx_clone = self.rx.resubscribe();
142→                    let session_id = self.session_id.clone();
143→                    let branch_id = self.branch_id.clone();
144→                    let last_seq = self.last_seq;
145→                    self.pending_fetch = false;
146→
147→                    tokio::spawn(async move {
148→                        // Wait for any notification, then wake the stream
149→                        loop {
150→                            match rx_clone.recv().await {
151→                                Ok(n) => {
152→                                    if n.session_id.as_str() == session_id.as_str()
153→                                        && n.branch_id.as_str() == branch_id.as_str()
154→                                        && n.seq > last_seq
155→                                    {
156→                                        break;
157→                                    }
158→                                }
159→                                Err(broadcast::error::RecvError::Lagged(_)) => {
160→                                    // Missed some notifications, wake anyway
161→                                    break;
162→                                }
163→                                Err(broadcast::error::RecvError::Closed) => {
164→                                    // Channel closed, wake to let stream return None eventually
165→                                    break;
166→                                }
167→                            }
168→                        }
169→                        waker.wake();
170→                    });
171→
172→                    // Mark that we should fetch when woken
173→                    self.pending_fetch = true;
174→                    return Poll::Pending;
175→                }
176→                Err(broadcast::error::TryRecvError::Closed) => {
177→                    // Channel closed, stream is done
178→                    return Poll::Ready(None);
179→                }
180→                Err(broadcast::error::TryRecvError::Lagged(_)) => {
181→                    // We missed some notifications; fetch whatever is new
182→                    match self.fetch_new_events() {
183→                        Ok(events) => {
184→                            for event in events {
185→                                self.buffer.push_back(event);
186→                            }
187→                            if let Some(event) = self.buffer.pop_front() {
188→                                self.last_seq = event.seq;
189→                                return Poll::Ready(Some(Ok(event)));
190→                            }
191→                            // No new events despite lag notification; continue polling
192→                        }
193→                        Err(e) => return Poll::Ready(Some(Err(e))),
194→                    }
195→                }
196→            }
197→        }
198→    }
199→}
