### 6. Canonical EventStorePort Adapter

**File:** `lago/crates/lago-aios-eventstore-adapter/src/lib.rs`

This is the **canonical EventStorePort implementation** that Autonomic should use:

```rust
pub struct LagoAiosEventStoreAdapter {
    journal: Arc<dyn Journal>,
}

#[async_trait]
impl EventStorePort for LagoAiosEventStoreAdapter {
    async fn append(&self, event: EventRecord) -> Result<EventRecord, KernelError> {
        let protocol_envelope = event.to_envelope();
        let lago_envelope = protocol_bridge::from_protocol(&protocol_envelope)?;
        let assigned_seq = self.journal.append(lago_envelope).await?;

        let mut persisted = event;
        persisted.sequence = assigned_seq;
        Ok(persisted)
    }

    async fn read(
        &self,
        session_id: ProtocolSessionId,
        branch_id: ProtocolBranchId,
        from_sequence: u64,
        limit: usize,
    ) -> Result<Vec<EventRecord>, KernelError> {
        let query = EventQuery::new()
            .session(session_id.into())
            .branch(branch_id.into())
            .after(from_sequence.saturating_sub(1))
            .limit(limit);
        let events = self.journal.read(query).await?;

        events.into_iter()
            .map(|envelope| {
                let protocol = envelope.to_protocol()?;
                envelope_to_record(protocol)
            })
            .collect()
    }

    async fn head(
        &self,
        session_id: ProtocolSessionId,
        branch_id: ProtocolBranchId,
    ) -> Result<u64, KernelError> {
        self.journal.head_seq(&session_id.into(), &branch_id.into()).await
    }

    async fn subscribe(
        &self,
        session_id: ProtocolSessionId,
        branch_id: ProtocolBranchId,
        after_sequence: u64,
    ) -> Result<EventRecordStream, KernelError> {
        let stream = self.journal.stream(session_id.into(), branch_id.into(), after_sequence).await?;

        let adapted = stream.filter_map(|item| async move {
            match item {
                Ok(envelope) => {
                    let protocol = envelope.to_protocol()?;
                    Some(envelope_to_record(protocol))
                }
                Err(e) => Some(Err(to_kernel_error(e))),
            }
        });

        Ok(Box::pin(adapted) as BoxStream<'static, Result<EventRecord, KernelError>>)
    }
}
```

**Critical Features:**
- **Protocol Bridge**: Converts between Lago and aios_protocol formats
- **Forward Compatibility**: Unknown events become `Custom {event_type, data}`
- **Subscription Pattern**: `subscribe()` returns `EventRecordStream` that replays existing + tails new
- **Error Handling**: Translates Lago errors to canonical `KernelError`

