 663→        let session = sessions
 664→            .get(session_id.as_str())
 665→            .with_context(|| format!("session not found: {session_id}"))?;
 666→
 667→        let mut branches: Vec<_> = session
 668→            .branches
 669→            .iter()
 670→            .map(|(branch_id, state)| BranchInfo {
 671→                branch_id: branch_id.clone(),
 672→                parent_branch: state.parent_branch.clone(),
 673→                fork_sequence: state.fork_sequence,
 674→                head_sequence: state.head_sequence,
 675→                merged_into: state.merged_into.clone(),
 676→            })
 677→            .collect();
 678→        branches.sort_by(|a, b| a.branch_id.as_str().cmp(b.branch_id.as_str()));
 679→        Ok(branches)
 680→    }
