1253→    fn branch_info(&self, session_id: &SessionId, branch_id: &BranchId) -> Result<BranchInfo> {
1254→        let sessions = self.sessions.lock();
1255→        let session = sessions
1256→            .get(session_id.as_str())
1257→            .with_context(|| format!("session not found: {session_id}"))?;
1258→        let state = session
1259→            .branches
1260→            .get(branch_id)
1261→            .with_context(|| format!("branch not found: {}", branch_id.as_str()))?;
1262→        Ok(BranchInfo {
1263→            branch_id: branch_id.clone(),
1264→            parent_branch: state.parent_branch.clone(),
1265→            fork_sequence: state.fork_sequence,
1266→            head_sequence: state.head_sequence,
1267→            merged_into: state.merged_into.clone(),
1268→        })
1269→    }
