1271→    fn should_checkpoint(&self, session_id: &SessionId) -> Result<bool> {
1272→        let mut sessions = self.sessions.lock();
1273→        let session = sessions
1274→            .get_mut(session_id.as_str())
1275→            .with_context(|| format!("session not found: {session_id}"))?;
1276→        session.tick_count += 1;
1277→        Ok(session.tick_count % self.config.checkpoint_every_ticks == 0)
1278→    }
