1280→    async fn create_checkpoint(
1281→        &self,
1282→        session_id: &SessionId,
1283→        branch_id: &BranchId,
1284→        manifest: &SessionManifest,
1285→        state: &AgentStateVector,
1286→    ) -> Result<CheckpointManifest> {
1287→        let checkpoint_id = CheckpointId::default();
1288→        let state_hash = sha256_json(state)?;
1289→        let checkpoint = CheckpointManifest {
1290→            checkpoint_id: checkpoint_id.clone(),
1291→            session_id: session_id.clone(),
1292→            branch_id: branch_id.clone(),
1293→            created_at: Utc::now(),
1294→            event_sequence: self.peek_last_sequence(session_id, branch_id)?,
1295→            state_hash,
1296→            note: "automatic heartbeat checkpoint".to_owned(),
1297→        };
1298→
1299→        let checkpoint_dir = PathBuf::from(&manifest.workspace_root)
1300→            .join("checkpoints")
1301→            .join(checkpoint_id.as_str());
1302→        fs::create_dir_all(&checkpoint_dir).await?;
1303→        self.write_pretty_json(checkpoint_dir.join("manifest.json"), &checkpoint)
1304→            .await?;
1305→        Ok(checkpoint)
1306→    }
