1455→fn model_stop_reason_string(stop_reason: &aios_protocol::ModelStopReason) -> String {
1456→    match stop_reason {
1457→        aios_protocol::ModelStopReason::Completed => "completed".to_owned(),
1458→        aios_protocol::ModelStopReason::ToolCall => "tool_call".to_owned(),
1459→        aios_protocol::ModelStopReason::MaxIterations => "max_iterations".to_owned(),
1460→        aios_protocol::ModelStopReason::Cancelled => "cancelled".to_owned(),
1461→        aios_protocol::ModelStopReason::Error => "error".to_owned(),
