 18→fn micros_to_datetime(timestamp_micros: u64) -> Result<DateTime<Utc>, KernelError> {
 19→    DateTime::<Utc>::from_timestamp_micros(timestamp_micros as i64).ok_or_else(|| {
 20→        KernelError::InvalidState(format!("invalid timestamp micros: {timestamp_micros}"))
 21→    })
 22→}
