1155→    fn cancellation_stops_run() {
1156→        let provider = ScriptedProvider {
1157→            turns: vec![
1158→                ModelTurn {
1159→                    directives: vec![ModelDirective::ToolCall {
1160→                        call: ToolCall {
1161→                            call_id: "c1".to_string(),
1162→                            tool_name: "echo".to_string(),
1163→                            input: json!({"value": "1"}),
1164→                        },
1165→                    }],
1166→                    stop_reason: ModelStopReason::ToolUse,
1167→                    usage: None,
1168→                },
1169→                ModelTurn {
1170→                    directives: vec![ModelDirective::FinalAnswer {
1171→                        text: "should not reach".to_string(),
1172→                    }],
1173→                    stop_reason: ModelStopReason::EndTurn,
1174→                    usage: None,
1175→                },
1176→            ],
1177→            cursor: Mutex::new(0),
1178→        };
1179→
1180→        let mut tools = ToolRegistry::default();
1181→        tools.register(EchoTool);
1182→
1183→        let orchestrator = Orchestrator::new(
1184→            Arc::new(provider),
1185→            tools,
1186→            Vec::new(),
1187→            OrchestratorConfig {
1188→                max_iterations: 10,
1189→                context: None,
1190→                context_compiler: None,
1191→            },
1192→        );
1193→
1194→        // Set cancellation flag before the second iteration
1195→        let cancel = Arc::new(AtomicBool::new(false));
1196→        let cancel_clone = cancel.clone();
1197→        let call_count = Arc::new(Mutex::new(0u32));
1198→        let call_count_clone = call_count.clone();
1199→
1200→        let output = orchestrator.run_cancellable(
1201→            RunInput {
1202→                run_id: "run-1".to_string(),
1203→                session_id: "s1".to_string(),
1204→                branch_id: "main".to_string(),
1205→                messages: vec![ChatMessage::user("test")],
1206→                state: AppState::default(),
1207→            },
1208→            Some(&cancel_clone),
1209→            move |event| {
1210→                // Cancel after first iteration completes
1211→                if matches!(event, AgentEvent::ToolCallCompleted { .. }) {
1212→                    let mut count = call_count_clone.lock().unwrap();
1213→                    *count += 1;
1214→                    if *count >= 1 {
1215→                        cancel.store(true, Ordering::Relaxed);
1216→                    }
1217→                }
1218→            },
1219→        );
1220→
1221→        assert_eq!(output.reason, RunStopReason::Cancelled);
1222→        // Should not have a final answer since we cancelled
1223→        assert!(output.final_answer.is_none());
1224→    }
