File: `autonomic-api/src/routes.rs`

```rust
pub fn create_router(
    controller: Arc<Mutex<ControllerEngine>>,
    projections: Arc<RwLock<HashMap<String, CostProjection>>>,
) -> Router {
    Router::new()
        .route("/health", get(health))
        .route("/gating/{session_id}", get(get_gating))
        .route("/projection/{session_id}", get(get_projection))
        .with_state(ApiState { controller, projections })
}

async fn get_gating(
    Path(session_id): Path<String>,
    State(state): State<ApiState>,
) -> Json<AutonomicGatingProfile> {
    let projections = state.projections.read().await;
    let projection = projections.get(&session_id)
        .cloned()
        .unwrap_or_default();
    let now_ms = /* current time in ms */;
    let mut controller = state.controller.lock().await;
    let profile = controller.evaluate(&projection, now_ms);
    Json(profile)
}
